sql:
SELECT total_vote, total_electors, turnout_percentage
FROM voter_statistics
WHERE poll_id = 1;

SELECT SUM(total_vote) AS total_votes_cast
FROM voter_statistics
WHERE poll_id = 0;

SELECT poll_id, AVG(turnout_percentage) AS average_turnout
FROM voter_statistics
GROUP BY poll_id;

external_knowledge:
- "champions" refers to the candidates with the highest total votes in each district; 
- "strongholds" refers to the districts where the candidates won; 
- "identities" refers to the candidate IDs and names; 
- "total conquests" refers to the total votes received by the winning candidates; 
- "fervor of their supporters" refers to the voter turnout percentage in each district.
